import{_ as s,o as a,c as t,aA as i}from"./chunks/framework.CAIZw9CR.js";const g=JSON.parse('{"title":"Directives","description":"","frontmatter":{},"headers":[],"relativePath":"krk/directives.md","filePath":"krk/directives.md","lastUpdated":null}'),n={name:"krk/directives.md"};function o(p,e,l,d,c,r){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="Directives" tabindex="-1">Directives <a class="header-anchor" href="#Directives" aria-label="Permalink to &quot;Directives {#Directives}&quot;">​</a></h1><p>A .krk file is a sequence of line-oriented directives. The parser recognizes the following top-level keywords (see <code>_parse_kraken_internal_single</code> in <code>src/io/kraken_parser.jl</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Simulation, Domain, Physics, Define, Obstacle, Fluid, Boundary,</span></span>
<span class="line"><span>Refine, Initial, Velocity, Module, Run, Output, Diagnostics,</span></span>
<span class="line"><span>Rheology, Setup, Preset, Sweep</span></span></code></pre></div><p>Unknown keywords trigger a Levenshtein-based <em>did you mean?</em> suggestion.</p><h2 id="Simulation" tabindex="-1">Simulation <a class="header-anchor" href="#Simulation" aria-label="Permalink to &quot;Simulation {#Simulation}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Simulation &lt;name&gt; &lt;lattice&gt;</code></p><ul><li><p><code>name</code> — identifier used in output directory names and logs.</p></li><li><p><code>lattice</code> — <code>D2Q9</code> (2D) or <code>D3Q19</code> (3D). Nothing else is accepted.</p></li></ul><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Simulation cavity_2d D2Q9</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_simulation</code></p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> _parse_simulation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(line</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    tokens </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> split</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(line)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tokens) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> throw</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ArgumentError</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Simulation needs name and lattice: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$line</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tokens[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lattice </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Symbol</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tokens[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lattice </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:D2Q9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:D3Q19</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> throw</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ArgumentError</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Unknown lattice &#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$lattice</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;. Use D2Q9 or D3Q19&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> name, lattice</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><h2 id="Domain" tabindex="-1">Domain <a class="header-anchor" href="#Domain" aria-label="Permalink to &quot;Domain {#Domain}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Domain L = &lt;Lx&gt; x &lt;Ly&gt; [x &lt;Lz&gt;] N = &lt;Nx&gt; x &lt;Ny&gt; [x &lt;Nz&gt;]</code></p><p>Physical extents (<code>L</code>) and grid resolution (<code>N</code>), separated by a literal <code>x</code>. Values can be numeric literals or identifiers previously declared with <code>Define</code>. The 3D component is optional in 2D.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Define N = 128</span></span>
<span class="line"><span>Domain L = 1.0 x 1.0   N = N x N</span></span>
<span class="line"><span>Domain L = 2.0 x 1.0 x 1.0  N = 128 x 64 x 64</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_domain</code> — accepts bare numbers or user variables via <code>_eval_domain_value</code>. Kwargs passed to <code>load_kraken(...; Nx=256)</code> override the file defaults.</p><h2 id="Physics" tabindex="-1">Physics <a class="header-anchor" href="#Physics" aria-label="Permalink to &quot;Physics {#Physics}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Physics key1 = val1 key2 = val2 ...</code></p><p>Physical parameters stored in a <code>Dict{Symbol,Float64}</code>. Special keys <code>Fx</code>, <code>Fy</code>, <code>Fz</code> become body-force expressions. Values can be numeric literals or simple expressions referencing <code>Define</code> variables.</p><p>Common keys: <code>nu</code> (kinematic viscosity, lattice units), <code>Pr</code> (Prandtl), <code>Ra</code> (Rayleigh), <code>alpha</code> (thermal diffusivity), <code>gbeta_DT</code> (buoyancy), <code>Fx</code>/<code>Fy</code>/<code>Fz</code> (body force).</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Define Re = 1000</span></span>
<span class="line"><span>Physics nu = 0.01 Pr = 0.71 Ra = 1e5</span></span>
<span class="line"><span>Physics nu = 0.1 Fx = 1e-5</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_physics</code>.</p><h2 id="Define" tabindex="-1">Define <a class="header-anchor" href="#Define" aria-label="Permalink to &quot;Define {#Define}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Define &lt;NAME&gt; = &lt;literal&gt;</code></p><p>Declare a user variable used in other directives. Overridable via kwargs to <code>load_kraken</code>. First-pass scanned before anything else; kwargs win over the file value.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Define Re  = 1000</span></span>
<span class="line"><span>Define N   = 128</span></span>
<span class="line"><span>Define Lid = 0.1</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_define</code>.</p><h2 id="Boundary" tabindex="-1">Boundary <a class="header-anchor" href="#Boundary" aria-label="Permalink to &quot;Boundary {#Boundary}&quot;">​</a></h2><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Boundary &lt;face&gt; &lt;type&gt;(key = val, ...)</span></span>
<span class="line"><span>Boundary &lt;face&gt; wall                       # simple form, no parentheses</span></span>
<span class="line"><span>Boundary &lt;face&gt; wall T = 1.0               # simple form with trailing kwargs</span></span>
<span class="line"><span>Boundary &lt;axis&gt; periodic                   # shorthand: axis ∈ {x, y, z}</span></span></code></pre></div><p><code>&lt;face&gt;</code> is one of <code>north</code>, <code>south</code>, <code>east</code>, <code>west</code> (2D) or additionally <code>top</code>, <code>bottom</code> (3D only). Some parser aliases are reserved for development modules; see <a href="./aliases">Aliases</a>. <code>&lt;type&gt;</code> is one of <code>wall</code>, <code>velocity</code>, <code>pressure</code>, <code>periodic</code>, <code>symmetry</code> — see <a href="./bc_types">BC types</a>.</p><p>The <code>Boundary x periodic</code> shorthand expands to a pair of <code>:periodic</code> BoundarySetup entries for the east/west (or north/south) faces.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Boundary north velocity(ux = 0.1, uy = 0)</span></span>
<span class="line"><span>Boundary south wall</span></span>
<span class="line"><span>Boundary x     periodic</span></span>
<span class="line"><span>Boundary north wall T = 0.0</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_boundary</code> (see the <a href="./bc_types">BC types</a> page for the full excerpt).</p><h2 id="Refine" tabindex="-1">Refine <a class="header-anchor" href="#Refine" aria-label="Permalink to &quot;Refine {#Refine}&quot;">​</a></h2><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Refine &lt;name&gt; { region = [x0, y0, x1, y1], ratio = 2, parent = &lt;name&gt; }</span></span></code></pre></div><p>Declare a nested refinement patch over an axis-aligned box. <code>ratio</code> defaults to <code>2</code>; <code>parent</code> defaults to <code>&quot;&quot;</code> (the base grid).</p><p><strong>Status in this branch:</strong> parser-only. <code>run_simulation</code> rejects non-empty <code>setup.refinements</code> in v0.1.0. Keep this directive for reading/development compatibility, but do not use it as a public runtime feature here.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Refine nearwall { region = [0.0, 0.0, 1.0, 0.1], ratio = 2 }</span></span>
<span class="line"><span>Refine tip     { region = [0.4, 0.0, 0.6, 0.1], ratio = 2, parent = nearwall }</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_refine</code>.</p><h2 id="Initial-/-Velocity" tabindex="-1">Initial / Velocity <a class="header-anchor" href="#Initial-/-Velocity" aria-label="Permalink to &quot;Initial / Velocity {#Initial-/-Velocity}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Initial { field = expr field = expr ... }</code></p><p>Initial fields are parsed into a <code>Dict{Symbol,KrakenExpr}</code> with keys like <code>ux</code>, <code>uy</code>, <code>uz</code>, <code>T</code>, <code>C</code>, <code>rho</code>. <code>Velocity { ... }</code> uses the exact same syntax and is an alias specifically for prescribed velocity fields (used by some runners to impose a frozen background flow).</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initial  { ux = 0.05*sin(2*pi*x) uy = -0.05*cos(2*pi*y) }</span></span>
<span class="line"><span>Velocity { ux = 0.1*(1 - (y/Ly)^2) uy = 0 }</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_initial</code>.</p><h2 id="Module" tabindex="-1">Module <a class="header-anchor" href="#Module" aria-label="Permalink to &quot;Module {#Module}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Module &lt;name&gt;</code></p><p>Activate an optional physics module. <code>thermal</code> is public in this branch. Other advanced names may parse but are rejected by the runner. See <a href="./modules">Modules</a>.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Module thermal</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_module</code>.</p><h2 id="Run" tabindex="-1">Run <a class="header-anchor" href="#Run" aria-label="Permalink to &quot;Run {#Run}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Run &lt;N&gt; steps</code></p><p>Total number of LBM time steps. The word <code>steps</code> is cosmetic — any non-digit tail is ignored.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Run 10000 steps</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_run</code>.</p><h2 id="Output" tabindex="-1">Output <a class="header-anchor" href="#Output" aria-label="Permalink to &quot;Output {#Output}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Output &lt;format&gt; every &lt;N&gt; [field1, field2, ...]</code></p><p>Periodic output of fields. <code>format</code> is typically <code>vtk</code>; <code>N</code> is the interval in time steps; the bracket list enumerates fields (<code>ux</code>, <code>uy</code>, <code>rho</code>, <code>T</code>, <code>C</code>, …). Output directory defaults to <code>output/</code>.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Output vtk every 500 [ux, uy, rho, T]</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_output</code>.</p><h2 id="Diagnostics" tabindex="-1">Diagnostics <a class="header-anchor" href="#Diagnostics" aria-label="Permalink to &quot;Diagnostics {#Diagnostics}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Diagnostics every &lt;N&gt; [col1, col2, ...]</code></p><p>Periodic scalar diagnostics (kinetic energy, Nusselt number, mass, …) logged to stdout and/or CSV.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Diagnostics every 100 [step, time, KE, uMax, Nu]</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_diagnostics</code>.</p><h2 id="Obstacle-/-Fluid" tabindex="-1">Obstacle / Fluid <a class="header-anchor" href="#Obstacle-/-Fluid" aria-label="Permalink to &quot;Obstacle / Fluid {#Obstacle-/-Fluid}&quot;">​</a></h2><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Obstacle &lt;name&gt; [wall(T = ..., ...)] { &lt;condition&gt; }</span></span>
<span class="line"><span>Obstacle &lt;name&gt; stl(file = &quot;path.stl&quot;, scale = ..., translate = [x, y, z])</span></span>
<span class="line"><span>Fluid    &lt;name&gt; { &lt;condition&gt; }</span></span></code></pre></div><p>Declare a solid obstacle or a fluid region by a condition expression <code>(x, y [, z]) -&gt; Bool</code>. The optional <code>wall(...)</code> block attaches boundary-condition values to the obstacle (for example temperature).</p><p>The parser also understands <code>stl(...)</code> parameters, but STL voxelization is not implemented by the v0.1.0 runner in this branch. Use expression-based geometry for public examples.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Obstacle disk wall(T = 1.0) { (x - 0.5)^2 + (y - 0.5)^2 &lt; 0.01 }</span></span>
<span class="line"><span>Fluid    jet  { y &lt; 0.2 }</span></span></code></pre></div><h2 id="Setup" tabindex="-1">Setup <a class="header-anchor" href="#Setup" aria-label="Permalink to &quot;Setup {#Setup}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Setup key = val key = val ...</code></p><p>Non-dimensional helper directive — see <a href="./helpers">Helpers</a> for the back-computation formulas. Known keys: <code>reynolds</code>, <code>rayleigh</code>, <code>prandtl</code>, <code>L_ref</code>, <code>U_ref</code>.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Setup reynolds = 1000</span></span>
<span class="line"><span>Setup rayleigh = 1e5 prandtl = 0.71</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_setup</code>.</p><h2 id="Preset" tabindex="-1">Preset <a class="header-anchor" href="#Preset" aria-label="Permalink to &quot;Preset {#Preset}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Preset &lt;name&gt;</code></p><p>Expand a canonical case into its constituent directives before any other parsing happens. See <a href="./presets">Presets</a> for the 5 presets and their exact expansions.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Preset cavity_2d</span></span></code></pre></div><p><strong>Parser:</strong> <code>_expand_preset</code> + <code>_preset_lines</code>.</p><h2 id="Sweep" tabindex="-1">Sweep <a class="header-anchor" href="#Sweep" aria-label="Permalink to &quot;Sweep {#Sweep}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Sweep &lt;param&gt; = [v1, v2, v3, ...]</code></p><p>Cartesian-product parameter sweep. Each combination produces one <code>SimulationSetup</code>. Parse with <code>parse_kraken_sweep</code> / <code>load_kraken_sweep</code> (which always return a <code>Vector{SimulationSetup}</code>).</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sweep Re = [100, 400, 1000]</span></span>
<span class="line"><span>Sweep N  = [64, 128, 256]</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_sweep</code>, driver in <code>_parse_kraken_internal</code>.</p><h2 id="Rheology" tabindex="-1">Rheology <a class="header-anchor" href="#Rheology" aria-label="Permalink to &quot;Rheology {#Rheology}&quot;">​</a></h2><p><strong>Syntax:</strong> <code>Rheology [phase] &lt;model&gt; { key = value ... }</code></p><p>Per-phase non-Newtonian constitutive model. <code>phase</code> is <code>liquid</code>, <code>gas</code>, or <code>default</code>; <code>&lt;model&gt;</code> is one of <code>newtonian</code>, <code>power_law</code>, <code>carreau</code>, <code>cross</code>, <code>bingham</code>, <code>herschel_bulkley</code>, <code>oldroyd_b</code>, <code>fene_p</code>, <code>saramito</code>.</p><p><strong>Example</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rheology power_law { K = 0.1 n = 0.5 }</span></span>
<span class="line"><span>Rheology liquid carreau { eta_0 = 1.0 eta_inf = 0.01 lambda = 1.0 a = 2.0 n = 0.5 }</span></span></code></pre></div><p><strong>Parser:</strong> <code>_parse_rheology</code> + <code>build_rheology_model</code>.</p>`,107)])])}const u=s(n,[["render",o]]);export{g as __pageData,u as default};
